SELECT d.*, o.member_nm, o.order_date, o.order_status_cd, v.vendor_nm, cd_ds.code_label AS dliv_status_cd_nm, cd_dt.code_label AS dliv_type_cd_nm, cd_dd.code_label AS dliv_div_cd_nm, cd_oc.code_label AS outbound_courier_cd_nm, cd_ic.code_label AS inbound_courier_cd_nm FROM od_dliv d LEFT JOIN od_order o ON o.order_id = d.order_id LEFT JOIN sy_vendor v ON v.vendor_id = d.vendor_id LEFT JOIN sy_code cd_ds ON cd_ds.code_grp = 'DLIV_STATUS' AND cd_ds.code_value = d.dliv_status_cd LEFT JOIN sy_code cd_dt ON cd_dt.code_grp = 'DLIV_TYPE' AND cd_dt.code_value = d.dliv_type_cd LEFT JOIN sy_code cd_dd ON cd_dd.code_grp = 'DLIV_DIV' AND cd_dd.code_value = d.dliv_div_cd LEFT JOIN sy_code cd_oc ON cd_oc.code_grp = 'COURIER' AND cd_oc.code_value = d.outbound_courier_cd LEFT JOIN sy_code cd_ic ON cd_ic.code_grp = 'COURIER' AND cd_ic.code_value = d.inbound_courier_cd
ORDER BY d.dliv_id ASC ORDER BY d.dliv_id DESC ORDER BY d.member_nm ASC ORDER BY d.member_nm DESC ORDER BY d.reg_date ASC ORDER BY d.reg_date DESC ORDER BY d.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT d.*, o.member_nm, o.order_date, o.order_status_cd, v.vendor_nm, cd_ds.code_label AS dliv_status_cd_nm, cd_dt.code_label AS dliv_type_cd_nm, cd_dd.code_label AS dliv_div_cd_nm, cd_oc.code_label AS outbound_courier_cd_nm, cd_ic.code_label AS inbound_courier_cd_nm FROM od_dliv d LEFT JOIN od_order o ON o.order_id = d.order_id LEFT JOIN sy_vendor v ON v.vendor_id = d.vendor_id LEFT JOIN sy_code cd_ds ON cd_ds.code_grp = 'DLIV_STATUS' AND cd_ds.code_value = d.dliv_status_cd LEFT JOIN sy_code cd_dt ON cd_dt.code_grp = 'DLIV_TYPE' AND cd_dt.code_value = d.dliv_type_cd LEFT JOIN sy_code cd_dd ON cd_dd.code_grp = 'DLIV_DIV' AND cd_dd.code_value = d.dliv_div_cd LEFT JOIN sy_code cd_oc ON cd_oc.code_grp = 'COURIER' AND cd_oc.code_value = d.outbound_courier_cd LEFT JOIN sy_code cd_ic ON cd_ic.code_grp = 'COURIER' AND cd_ic.code_value = d.inbound_courier_cd
ORDER BY d.dliv_id ASC ORDER BY d.dliv_id DESC ORDER BY d.member_nm ASC ORDER BY d.member_nm DESC ORDER BY d.reg_date ASC ORDER BY d.reg_date DESC ORDER BY d.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

