UPDATE od_dliv
dliv_status_cd = #{dlivStatusCd}, dliv_status_cd_before = #{dlivStatusCdBefore}, outbound_courier_cd = #{outboundCourierCd}, outbound_tracking_no = #{outboundTrackingNo}, dliv_ship_date = #{dlivShipDate}, dliv_date = #{dlivDate}, dliv_memo = #{dlivMemo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE dliv_id = #{dlivId}
